import{_ as a,o as r,c as t,a0 as o}from"./chunks/framework.jwovEGr5.js";const p=JSON.parse('{"title":"Alliance Player Guide","description":"","frontmatter":{},"headers":[],"relativePath":"roles/viewer.md","filePath":"roles/viewer.md"}'),i={name:"roles/viewer.md"};function l(n,e,s,d,c,h){return r(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="alliance-player-guide" tabindex="-1">Alliance Player Guide <a class="header-anchor" href="#alliance-player-guide" aria-label="Permalink to &quot;Alliance Player Guide&quot;">​</a></h1><p>This is the <strong>start here</strong> guide for <code>Alliance Player</code> users. It is the shortest role guide because this role is mostly read-only.</p><h2 id="what-you-can-do" tabindex="-1">What you can do <a class="header-anchor" href="#what-you-can-do" aria-label="Permalink to &quot;What you can do&quot;">​</a></h2><p>Alliance Players can mainly:</p><ul><li>read dashboards</li><li>read players and event information</li><li>read analytics they are allowed to see</li><li>read rewards</li><li>file reports</li></ul><p>Start with:</p><ul><li><a href="./../getting-started/navigating.html">Finding Your Way Around</a></li><li><a href="./../getting-started/dashboard-tour.html">Reading the Dashboard</a></li><li><a href="./../how-to/players-directory.html">Browse &amp; Filter Players</a></li><li><a href="./../how-to/player-profile.html">Read a Player Profile</a></li><li><a href="./../analytics/overview.html">Analytics Overview</a></li><li><a href="./../how-to/rewards.html">Review Reward Eligibility</a></li></ul><h2 id="what-you-cannot-do" tabindex="-1">What you cannot do <a class="header-anchor" href="#what-you-cannot-do" aria-label="Permalink to &quot;What you cannot do&quot;">​</a></h2><p>Alliance Players cannot:</p><ul><li>create or edit records</li><li>upload imports</li><li>enter manual results</li><li>manage settings</li><li>request subscriptions directly</li></ul><p>If you need something changed, ask your <code>Alliance Leader</code> or <code>Co-Leader</code>.</p><h2 id="reports-your-main-action-path" tabindex="-1">Reports: your main action path <a class="header-anchor" href="#reports-your-main-action-path" aria-label="Permalink to &quot;Reports: your main action path&quot;">​</a></h2><p>Your most useful write action is reporting a problem or asking for help.</p><p>Read:</p><ul><li><a href="./../how-to/reports.html">File &amp; Track Reports</a></li></ul><p>If the issue is specifically about restoring something deleted, that report may lead to the restore flow described in <a href="./../how-to/restore-requests.html">Request &amp; Approve Restores</a>.</p><h2 id="when-you-need-account-changes" tabindex="-1">When you need account changes <a class="header-anchor" href="#when-you-need-account-changes" aria-label="Permalink to &quot;When you need account changes&quot;">​</a></h2><p>If your profile, role, or access needs to change, contact your alliance leadership first. They can either handle it directly or escalate it to a <code>King</code> or <code>Supreme Admin</code>.</p>',18)])])}const y=a(i,[["render",l]]);export{p as __pageData,y as default};
